-- Forkcast seed (idempotent). Owner resolved by email at apply time.
do $$
declare o uuid;
begin
  select id into o from auth.users where email = 'petertheoomen@gmail.com' limit 1;
  if o is null then raise exception 'Owner % not found in auth.users', 'petertheoomen@gmail.com'; end if;

  on conflict (owner_id, name) do nothing;

  on conflict (owner_id, name) do nothing;

  on conflict (owner_id, name) do nothing;
end $$;
